class Solution:
    def maximumProfit(self, prices, k):
        import sys
        from functools import lru_cache
        sys.setrecursionlimit(1000000)
        n = len(prices)
        NEG = float('-inf')
        @lru_cache(maxsize=None)
        def rec(i, t, state):
            if i >= n or t == 0:
                return 0 if state == 0 else NEG
            best = rec(i + 1, t, state)
            p = prices[i]
            if state == 0:
                best = max(best, -p + rec(i + 1, t, 1))
                best = max(best, p + rec(i + 1, t, 2))
            elif state == 1:
                best = max(best, p + rec(i + 1, t - 1, 0))
            else:
                best = max(best, -p + rec(i + 1, t - 1, 0))
            return best
        ans = rec(0, k, 0)
        rec.cache_clear()
        return ans

