class Solution:
    def maximumProfit(self, prices, k):
        NEG = float('-inf')
        f = [[NEG, NEG, NEG] for _ in range(k + 1)]
        for t in range(k + 1):
            f[t][0] = 0
        for p in prices:
            ng = [row[:] for row in f]
            for t in range(k + 1):
                if f[t][0] != NEG:
                    if f[t][0] - p > ng[t][1]:
                        ng[t][1] = f[t][0] - p
                    if f[t][0] + p > ng[t][2]:
                        ng[t][2] = f[t][0] + p
                if t + 1 <= k:
                    if f[t][1] != NEG and f[t][1] + p > ng[t + 1][0]:
                        ng[t + 1][0] = f[t][1] + p
                    if f[t][2] != NEG and f[t][2] - p > ng[t + 1][0]:
                        ng[t + 1][0] = f[t][2] - p
            f = ng
        return max(f[t][0] for t in range(k + 1))

