var maximumProfit = function(prices, k) {
    const NEG = -Infinity;
    let f = [];
    for (let t = 0; t <= k; t++) f.push([0, NEG, NEG]);
    for (const p of prices) {
        const ng = f.map(row => row.slice());
        for (let t = 0; t <= k; t++) {
            if (f[t][0] !== NEG) {
                if (f[t][0] - p > ng[t][1]) ng[t][1] = f[t][0] - p;
                if (f[t][0] + p > ng[t][2]) ng[t][2] = f[t][0] + p;
            }
            if (t + 1 <= k) {
                if (f[t][1] !== NEG && f[t][1] + p > ng[t + 1][0]) ng[t + 1][0] = f[t][1] + p;
                if (f[t][2] !== NEG && f[t][2] - p > ng[t + 1][0]) ng[t + 1][0] = f[t][2] - p;
            }
        }
        f = ng;
    }
    let best = 0;
    for (let t = 0; t <= k; t++) if (f[t][0] > best) best = f[t][0];
    return best;
};
